// ====================================================================================
// Thermodynamic indices
// ====================================================================================
describe('Thermodynamic Indices', () => {
    test('pw (precipitable water)', () => {
        expect(stats.pw).toBeCloseTo(ref.pw, PRECISE_DIGITS);
    });
    test('tei (theta-e index)', () => {
        expect(stats.tei).toBeCloseTo(ref.tei, KINEMATIC_DIGITS);
    });
    test('dcape', () => {
        // DCAPE algorithms differ significantly between implementations (~10%)
        expect(stats.dcape).toBeCloseTo(ref.dcape, -3);
    });
    test('kIndex', () => {
        expect(stats.kIndex).toBeCloseTo(ref.kIndex, SCALAR_DIGITS);
    });
    test('tTotals (total totals)', () => {
        expect(stats.tTotals).toBeCloseTo(ref.tTotals, SCALAR_DIGITS);
    });
    test('meanMR (mean mixing ratio)', () => {
        expect(stats.meanMR).toBeCloseTo(ref.meanMR, SCALAR_DIGITS);
    });
    test('cTemp (convective temperature)', () => {
        expect(stats.cTemp).toBeCloseTo(ref.cTemp, KINEMATIC_DIGITS);
    });
    test('maxT (max temperature)', () => {
        expect(stats.maxT).toBeCloseTo(ref.maxT, SCALAR_DIGITS);
    });
    test('Mean Theta-E', () => {
        expect(sharp.meanThetae(profile, 1000, 500) + 273.15).toBeCloseTo(
            ref.meanThetaE,
            KINEMATIC_DIGITS,
        );
    });
    test('lowRH (sfc to sfc-100 mean RH)', () => {
        expect(stats.lowRH).toBeCloseTo(ref.lowRH, SCALAR_DIGITS);
    });
    test('midRH (sfc-150 to sfc-350 mean RH)', () => {
        expect(stats.midRH).toBeCloseTo(ref.midRH, SCALAR_DIGITS);
    });
});

